    fun byId(id: Int?): ReynimeSeries? = id?.let { value -> series.firstOrNull { it.id == value } }

    fun bySlug(slug: String?): ReynimeSeries? {
        val clean = slug?.trim()?.lowercase().orEmpty()
        if (clean.isBlank()) return null
        return series.firstOrNull { it.slug == clean }
    }
